@media (max-width: 1350px) {

  header, main, footer {
    width: 50%;
  }

  .sidenote,
  .marginnote,
  figcaption {
    margin-right: -55%;
    width: 50%;
  }

  .wide {
    width: 155%;
  }

}

/* intermédiaire : le main text est collé à gauche (burger ?) mais quand même les sidenotes */
@media (max-width: 1000px) {

  header, main, footer {
    margin-left: 20pt;
    width: 65%;
    margin-right: auto;
  }

  .sidenote, .marginnote, figcaption {
    margin-right: -45%;
    width: 40%;
  }

  .wide {
    width: 145%;
  }

}

